/**
 * Contract Test: Digest Generator Schedule Management
 * T015 - MUST FAIL before implementation
 *
 * This test validates the digest schedule management endpoints according to the OpenAPI contract.
 * The endpoints must handle digest scheduling configuration including category-specific timing,
 * delivery preferences, and template assignments.
 */

import { describe, test, expect, beforeAll } from '@jest/globals';
import { DigestGenerator } from '../../src/digest/digest-generator';

describe('Digest Generator Schedule Management Contract', () => {
  let digestGenerator: DigestGenerator;

  beforeAll(() => {
    // This will fail until DigestGenerator is implemented
    digestGenerator = new DigestGenerator();
  });

  test('GET /schedule - should retrieve current digest schedule configuration', async () => {
    // This should fail until the schedule management is implemented
    const result = await digestGenerator.getSchedule();

    // Contract assertions - these define what the implementation must return
    expect(result).toMatchObject({
      dailyDigest: expect.objectContaining({
        enabled: expect.any(Boolean),
        time: expect.stringMatching(/^([01]?[0-9]|2[0-3]):[0-5][0-9]$/),
        template: expect.any(String),
        categories: expect.any(Array),
        minEmailCount: expect.any(Number),
      }),
      weeklyDigest: expect.objectContaining({
        enabled: expect.any(Boolean),
        time: expect.stringMatching(/^([01]?[0-9]|2[0-3]):[0-5][0-9]$/),
        template: expect.any(String),
        categories: expect.any(Array),
        minEmailCount: expect.any(Number),
      }),
      categorySpecificSchedules: expect.any(Object),
      globalSettings: expect.objectContaining({
        timezone: expect.any(String),
        defaultTemplate: expect.any(String),
        recipientEmail: expect.stringMatching(/^[^\s@]+@[^\s@]+\.[^\s@]+$/),
        enabled: expect.any(Boolean),
      }),
    });

    // Validate time format (HH:MM)
    expect(result.dailyDigest.time).toMatch(/^([01]?[0-9]|2[0-3]):[0-5][0-9]$/);
    expect(result.weeklyDigest.time).toMatch(/^([01]?[0-9]|2[0-3]):[0-5][0-9]$/);

    // Validate timezone is valid format (either UTC or IANA format)
    const isUTC = result.globalSettings.timezone === 'UTC';
    const isIANA = /^[A-Za-z_]+\/[A-Za-z_]+$/.test(result.globalSettings.timezone);
    expect(isUTC || isIANA).toBe(true);

    // Validate minEmailCount is non-negative
    expect(result.dailyDigest.minEmailCount).toBeGreaterThanOrEqual(0);
    expect(result.weeklyDigest.minEmailCount).toBeGreaterThanOrEqual(0);
  });

  test('PUT /schedule - should update digest schedule configuration', async () => {
    const updatedSchedule = {
      dailyDigest: {
        enabled: true,
        time: '08:00',
        template: 'modern-daily',
        categories: ['receipts', 'notifications', 'updates'],
        minEmailCount: 1,
      },
      weeklyDigest: {
        enabled: true,
        time: '09:00',
        template: 'comprehensive-weekly',
        categories: ['newsletters', 'promotions', 'social'],
        minEmailCount: 5,
      },
      categorySpecificSchedules: {
        receipts: {
          digestType: 'daily' as const,
          priority: 1,
          template: 'receipt-focused',
          customSummary: true,
        },
        newsletters: {
          digestType: 'weekly' as const,
          priority: 2,
          customSummary: false,
        },
      },
      globalSettings: {
        timezone: 'America/New_York',
        defaultTemplate: 'modern-daily',
        recipientEmail: 'updated@example.com',
        enabled: true,
      },
    };

    const result = await digestGenerator.updateSchedule(updatedSchedule);

    // Should return the updated configuration
    expect(result).toMatchObject(updatedSchedule);

    // Validate specific updates were applied
    expect(result.dailyDigest.enabled).toBe(true);
    expect(result.dailyDigest.time).toBe('08:00');
    expect(result.dailyDigest.template).toBe('modern-daily');
    expect(result.globalSettings.recipientEmail).toBe('updated@example.com');
    expect(result.globalSettings.timezone).toBe('America/New_York');
  });

  test('PUT /schedule - should validate schedule configuration schema', async () => {
    const invalidSchedule = {
      dailyDigest: {
        enabled: true,
        time: '25:00', // Invalid hour
        template: 'modern-daily',
        categories: ['receipts'],
        minEmailCount: -1, // Invalid negative count
      },
      weeklyDigest: {
        enabled: true,
        time: '09:70', // Invalid minutes
        template: 'comprehensive-weekly',
        categories: ['newsletters'],
        minEmailCount: 5,
      },
      categorySpecificSchedules: {},
      globalSettings: {
        timezone: 'Invalid/Timezone',
        defaultTemplate: 'modern-daily',
        recipientEmail: 'invalid-email-format',
        enabled: true,
      },
    };

    await expect(digestGenerator.updateSchedule(invalidSchedule)).rejects.toThrow(/validation|time|email|timezone/i);
  });

  test('Schedule should support category-specific configurations', async () => {
    const categorySpecificSchedule = {
      dailyDigest: {
        enabled: true,
        time: '08:00',
        template: 'default',
        categories: [],
        minEmailCount: 0,
      },
      weeklyDigest: {
        enabled: false,
        time: '09:00',
        template: 'default',
        categories: [],
        minEmailCount: 0,
      },
      categorySpecificSchedules: {
        urgent: {
          digestType: 'daily' as const,
          priority: 1,
          template: 'urgent-alerts',
          customSummary: true,
        },
        receipts: {
          digestType: 'daily' as const,
          priority: 2,
          template: 'receipt-summary',
          customSummary: false,
        },
        newsletters: {
          digestType: 'weekly' as const,
          priority: 3,
          customSummary: false,
        },
        social: {
          digestType: 'weekly' as const,
          priority: 10,
          template: 'social-digest',
          customSummary: true,
        },
      },
      globalSettings: {
        timezone: 'UTC',
        defaultTemplate: 'default',
        recipientEmail: 'user@example.com',
        enabled: true,
      },
    };

    const result = await digestGenerator.updateSchedule(categorySpecificSchedule);

    // Validate category-specific schedules
    const categorySchedules = result.categorySpecificSchedules;

    expect(categorySchedules.urgent).toMatchObject({
      digestType: 'daily',
      priority: 1,
      template: 'urgent-alerts',
      customSummary: true,
    });

    expect(categorySchedules.receipts).toMatchObject({
      digestType: 'daily',
      priority: 2,
      template: 'receipt-summary',
      customSummary: false,
    });

    expect(categorySchedules.newsletters).toMatchObject({
      digestType: 'weekly',
      priority: 3,
      customSummary: false,
    });

    // Validate priority values are within valid range
    Object.values(categorySchedules).forEach(
      (schedule: { priority: number; digestType: string; template?: string; customSummary: boolean }) => {
        expect(schedule.priority).toBeGreaterThanOrEqual(1);
        expect(schedule.priority).toBeLessThanOrEqual(10);
        expect(['daily', 'weekly']).toContain(schedule.digestType);
      }
    );
  });

  test('Schedule should validate category priority uniqueness', async () => {
    const duplicatePrioritySchedule = {
      dailyDigest: {
        enabled: true,
        time: '08:00',
        template: 'default',
        categories: [],
        minEmailCount: 0,
      },
      weeklyDigest: {
        enabled: false,
        time: '09:00',
        template: 'default',
        categories: [],
        minEmailCount: 0,
      },
      categorySpecificSchedules: {
        urgent: {
          digestType: 'daily' as const,
          priority: 1,
          template: 'urgent-alerts',
          customSummary: true,
        },
        receipts: {
          digestType: 'daily' as const,
          priority: 1, // Duplicate priority
          template: 'receipt-summary',
          customSummary: false,
        },
      },
      globalSettings: {
        timezone: 'UTC',
        defaultTemplate: 'default',
        recipientEmail: 'user@example.com',
        enabled: true,
      },
    };

    await expect(digestGenerator.updateSchedule(duplicatePrioritySchedule)).rejects.toThrow(
      /priority|duplicate|conflict/i
    );
  });

  test('Schedule should support timezone validation', async () => {
    const validTimezones = [
      'UTC',
      'America/New_York',
      'Europe/London',
      'Asia/Tokyo',
      'Australia/Sydney',
      'America/Los_Angeles',
      'Europe/Paris',
    ];

    for (const timezone of validTimezones) {
      const scheduleWithTimezone = {
